#include <iostream>

class Point2D {
    int m_x{};
    int m_y{};
public:
    Point2D(int x, int y) : m_x{ x }, m_y{ y } {}

    Point2D operator+(const Point2D& rhs) const {
        return Point2D{ m_x + rhs.m_x, m_y + rhs.m_y };
    }

    int getX() const { return m_x; }
    int getY() const { return m_y; }
};

int main() {
    int x1{}, y1{}, x2{}, y2{};
    std::cin >> x1 >> y1 >> x2 >> y2;
    Point2D a{ x1, y1 };
    Point2D b{ x2, y2 };
    Point2D c{ a + b };
    std::cout << '(' << c.getX() << ", " << c.getY() << ")\n";
    return 0;
}

